public static FWFTextBlockGroup find(
    RefRecId    _recId,
    boolean     _update = false)
{
    FWFTextBlockGroup  textBlockGroup;

    textBlockGroup.selectForUpdate(_update);

    if (_recId)
    {
        select firstonly textBlockGroup
            where textBlockGroup.RecId == _recId;
    }

    return textBlockGroup;
}

public static FWFTextBlockGroup findGroupModule(
    FWFTextBlockGroupId _id,
    FWFTextBlockModule  _module,
    boolean             _update = false
    )
{
    FWFTextBlockGroup   textBlockGroup;

    textBlockGroup.selectForUpdate(_update);

    if (_id && _module)
    {
        select firstonly textBlockGroup
            where  textBlockGroup.Id	  == _id
               &&  textBlockGroup.Module  == _module;
    }

    return textBlockGroup;
}

public static void lookup(FormControl _control, FWFTextBlockModule _module)
{
    SysTableLookup sysTableLookup;

    sysTableLookup  = SysTableLookup::newParameters(tableNum(FWFTextBlockGroup), _control);

    sysTableLookup.addLookupfield(fieldNum(FWFTextBlockGroup, Id));
    sysTableLookup.addLookupfield(fieldNum(FWFTextBlockGroup, Description));
    sysTableLookup.parmQuery(FWFTextBlockGroup::lookupQuery(_module));

    sysTableLookup.performFormLookup();
}

public static query lookupQuery(FWFTextBlockModule	_module)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;

    qbds = query.addDataSource(tableNum(FWFTextBlockGroup));

    if (_module)
    {
        qbds.addRange(fieldNum(FWFTextBlockGroup, Module)).value(queryValue(_module));
    }

    return query;
}

public static boolean exist(FWFTextBlockGroupId _id,
                            FWFTextBlockModule  _module)
{
    FWFTextBlockGroup  textBlockGroup;

    if (_id && _module)
    {
        select firstonly RecId from textBlockGroup
            where  textBlockGroup.Id	  == _id
                &&  textBlockGroup.Module == _module;
    }

    return textBlockGroup.RecId != 0;
}
